class Solution:
    def frequencySort(self, nums):
        remaining = list(nums)
        freq = {}
        for x in remaining:
            freq[x] = freq.get(x, 0) + 1
        result = []
        while remaining:
            best = remaining[0]
            for x in remaining:
                if (freq[x], -x) < (freq[best], -best):
                    best = x
            count = 0
            kept = []
            for x in remaining:
                if x == best:
                    count += 1
                else:
                    kept.append(x)
            result.extend([best] * count)
            remaining = kept
        return result

